#!/usr/bin/env python3
"""Deterministically generate ``benchmark_many.xml`` -- the 800-element scaling
benchmark for ``ps_path_diff --bench``.

The model is a flat worldbody of ``N`` (default 800) independent bodies, each
carrying one joint and one geom, so every per-element compile stage scales
linearly with N: 800 bodies / 800 joints / 800 geoms. Geometry is varied by a
fixed rotation of a small primitive/joint palette (no RNG) so the file is
byte-identical on every run and reviewable as a checked-in artifact.

Run from anywhere::

    python gen_benchmark.py            # writes benchmark_many.xml beside this script
    python gen_benchmark.py --n 800 --out /path/to/benchmark_many.xml

Both the script and its generated output are checked in; regenerate and diff to
confirm nothing drifted.
"""

from __future__ import annotations

import argparse
from pathlib import Path

# Fixed palettes -- index by (i % len) so output is fully deterministic.
_GEOMS = [
    ('sphere', '0.03'),
    ('box', '0.03 0.04 0.05'),
    ('capsule', '0.02 0.05'),
    ('ellipsoid', '0.03 0.04 0.05'),
    ('cylinder', '0.03 0.05'),
]
_JOINTS = [
    ('hinge', '1 0 0'),
    ('hinge', '0 1 0'),
    ('slide', '0 0 1'),
    ('hinge', '0 0 1'),
    ('slide', '1 0 0'),
]


def build(n: int) -> str:
    lines: list[str] = []
    lines.append('<mujoco model="benchmark_many">')
    lines.append('  <!-- GENERATED by gen_benchmark.py; do not edit by hand. -->')
    lines.append('  <compiler angle="radian"/>')
    lines.append('  <option timestep="0.002"/>')
    lines.append('  <worldbody>')
    lines.append('    <geom name="floor" type="plane" size="20 20 0.1"/>')
    for i in range(n):
        # Lay the bodies out on a grid so none overlap and all stay finite.
        row, col = divmod(i, 40)
        x = 0.25 * col
        y = 0.25 * row
        gtype, gsize = _GEOMS[i % len(_GEOMS)]
        jtype, jaxis = _JOINTS[i % len(_JOINTS)]
        lines.append(f'    <body name="body_{i}" pos="{x:.3f} {y:.3f} 1.0">')
        lines.append(
            f'      <joint name="joint_{i}" type="{jtype}" axis="{jaxis}"/>'
        )
        lines.append(
            f'      <geom name="geom_{i}" type="{gtype}" size="{gsize}"/>'
        )
        lines.append('    </body>')
    lines.append('  </worldbody>')
    lines.append('  <actuator>')
    for i in range(n):
        lines.append(f'    <motor name="act_{i}" joint="joint_{i}"/>')
    lines.append('  </actuator>')
    lines.append('</mujoco>')
    return '\n'.join(lines) + '\n'


def main() -> None:
    ap = argparse.ArgumentParser()
    ap.add_argument('--n', type=int, default=800, help='number of bodies (default 800)')
    ap.add_argument(
        '--out',
        type=Path,
        default=Path(__file__).resolve().parent / 'benchmark_many.xml',
    )
    args = ap.parse_args()
    args.out.write_text(build(args.n), encoding='utf-8')
    print(f'wrote {args.out} ({args.n} bodies/joints/geoms)')


if __name__ == '__main__':
    main()
